+        // Simple OPFS support check (no internal OPFSStorage needed)
+        const opfsStorage = {
+            async isSupported() {
+                return typeof navigator !== 'undefined' &&
+                       navigator.storage &&
+                       typeof navigator.storage.getDirectory === 'function';
+            },
+            async getStats() {
+                if (!await this.isSupported()) return { used: 0, available: 0 };
+                try {
+                    const estimate = await navigator.storage.estimate();
+                    return { used: estimate.usage || 0, available: estimate.quota || 0 };
+                } catch { return { used: 0, available: 0 }; }
+            },
+            async listFiles() {
+                // Simplified - full file listing requires internal API
+                return [];
+            },
+            async delete() { /* no-op for simplified demo */ },
+            async clearAll() { return 0; },
+            async save() { /* no-op */ },
+            async load() { return null; }
+        };
+
+        // Helper to extract URL from read_lance('url') syntax
+        function extractUrlFromSql(sql) {
+            const match = sql.match(/read_lance\s*\(\s*['"]([^'"]+)['"]/i);
+            return match ? match[1] : null;
+        }
+
+        // Helper to check if SQL uses read_lance()
+        function hasRemoteUrl(sql) {
+            return /read_lance\s*\(/i.test(sql);
+        }

